import re


def validate_filename(name):
    if not name or len(name) > 255:
        return False
    return bool(re.match(r'^[a-zA-Z0-9._-]+$', name))


def sanitize_path(path):
    parts = path.replace('\\', '/').split('/')
    cleaned = [p for p in parts if p and p != '..' and p != '.']
    return '/'.join(cleaned)


def chunk_text(text, chunk_size):
    if not text or not text.strip():
        return []
    words = text.split()
    chunks = []
    current = ''
    for word in words:
        if not current:
            current = word
        elif len(current) + 1 + len(word) <= chunk_size:
            current += ' ' + word
        else:
            chunks.append(current)
            current = word
    if current:
        chunks.append(current)
    return chunks


def merge_lines(lines_a, lines_b):
    seen = set()
    result = []
    for line in list(lines_a) + list(lines_b):
        if line not in seen:
            seen.add(line)
            result.append(line)
    return result
